import React, { useState } from "react";
import { useAuth } from "../AuthContext";

export default function Login() {
    const { login } = useAuth();
    const [form, setForm] = useState({ username: "", password: "", remember: false });
    const [showPw, setShowPw] = useState(false);
    const [loading, setLoading] = useState(false);
    const [err, setErr] = useState("");

    const onChange = (e) => {
        const { name, value, type, checked } = e.target;
        setForm((s) => ({ ...s, [name]: type === "checkbox" ? checked : value }));
    };

    const onSubmit = async (e) => {
        e.preventDefault();
        setErr("");
        setLoading(true);
        try {
            await login(form.username, form.password, form.remember);
            window.location.href = "/crm.html"; // vào trang CRM tĩnh
        } catch (error) {
            const msg =
                error?.response?.data?.message ||
                error?.response?.data?.error ||
                error?.message ||
                "Đăng nhập thất bại";
            setErr(msg);
        } finally {
            setLoading(false);
        }
    };

    return (
        // ... (phần JSX form bạn đang dùng giữ nguyên)
        // Chỉ khác ở onSubmit gọi login với form.remember
        // và không dùng useNavigate ở đây nữa
        // (còn lại UI giữ y như trước)
        <div className="construction-gradient min-h-screen flex items-center justify-center p-4 relative font-[Inter]">
            {/* ... toàn bộ UI bạn đã có ... */}
            <form onSubmit={onSubmit} className="space-y-6">
                {/* ... inputs ... */}
                <div className="flex items-center">
                    <input
                        id="remember"
                        name="remember"
                        type="checkbox"
                        checked={form.remember}
                        onChange={onChange}
                        className="h-4 w-4 text-emerald-500 focus:ring-emerald-400 border-gray-300 rounded"
                    />
                    <label htmlFor="remember" className="ml-2 block text-sm text-gray-600">
                        Ghi nhớ đăng nhập
                    </label>
                </div>
                {/* ... button submit ... */}
            </form>
        </div>
    );
}
